    18→export class DynamoDBService {
    19→  private DynamoClient: DynamoDBClient;
    20→  private DynamoDocumentClient: DynamoDBDocumentClient;
    21→
    22→  constructor() {
    23→    this.DynamoClient = new DynamoDBClient({
    24→      apiVersion: '2012-08-10'
    25→    });
    26→
    27→    const marshallOptions = {
    28→      convertEmptyValues: false,
    29→      removeUndefinedValues: true,
    30→      convertClassInstanceToMap: false,
    31→    };
    32→    const unmarshallOptions = {
    33→      wrapNumbers: false,
    34→    };
    35→    const translateConfig = { marshallOptions, unmarshallOptions };
    36→
    37→    this.DynamoDocumentClient = DynamoDBDocumentClient.from(
    38→      this.DynamoClient,
    39→      translateConfig
    40→    );
    41→  }
    42→
    43→  async putItem(tableName: string, item: Record<string, any>) {
    44→    try {
    45→      const command = new PutCommand({
    46→        TableName: tableName,
    47→        Item: item,
    48→      });
