    50→      Console.info(`Item inserido na tabela ${tableName}`);
    51→    } catch (error) {
    52→      Console.error('Erro ao inserir item:', error);
    53→    }
    54→  }
    55→
    56→  async getItem(tableName: string, key: Record<string, any>) {
    57→    try {
    58→      const command = new GetCommand({
    59→        TableName: tableName,
    60→        Key: key,
    61→      });
    62→      const data = await this.DynamoDocumentClient.send(command);
