   153→  async getExistingItems<T>(tableName: string, keys: Record<string, any>[]): Promise<T[]> {
   154→    const existingItems: T[] = [];
   155→
   156→    const batches = [];
   157→    for (let i = 0; i < keys.length; i += MAX_BATCH_SIZE) {
   158→      batches.push(keys.slice(i, i + MAX_BATCH_SIZE));
   159→    }
   160→
   161→    for (const batch of batches) {
   162→      const command = new BatchGetCommand({
   163→        RequestItems: {
   164→          [tableName]: { Keys: batch },
   165→        },
   166→      });
   167→
   168→      try {
   169→        const result = await this.DynamoDocumentClient.send(command);
   170→
   171→        const items = result.Responses?.[tableName];
   172→        if (items) {
   173→          existingItems.push(...(items as T[]));
   174→        }
   175→      } catch (error) {
   176→        Console.error('Erro ao buscar itens em batch:', error);
   177→      }
   178→    }
   179→
   180→    return existingItems;
   181→  }
   182→
   183→  async batchItems<T>(tableName: string, items: T[], pkName: string): Promise<T[]> {
   184→    const chunks = [];
   185→
   186→    while (items.length) {
   187→        chunks.push(items.splice(0, MAX_BATCH_SIZE));
   188→    }
   189→
   190→    const unprocessedItems: T[] = [];
   191→
   192→    for (const chunk of chunks) {
   193→        const uniqueItems = this.removeDuplicates(chunk)
   194→
   195→        const writeRequests = uniqueItems.map((item) => ({
   196→            PutRequest: {
   197→                Item: item as Record<string, any>,
   198→            },
   199→        }));
   200→
   201→        const command = new BatchWriteCommand({
   202→            RequestItems: {
   203→                [tableName]: writeRequests,
   204→            },
   205→        });
   206→
   207→        try {
   208→            const result = await this.DynamoDocumentClient.send(command);
   209→            Console.info(`Itens inseridos na tabela ${tableName}`);
   210→
   211→            if (result.UnprocessedItems && result.UnprocessedItems[tableName]?.length > 0) {
   212→                Console.info(`Existem itens não processados: ${result.UnprocessedItems[tableName].length}`);
   213→
   214→                const missingKeys = result.UnprocessedItems[tableName].map((el: any) => el.PutRequest.Item[pkName]);
   215→                const missingItems = chunk.filter((item: any) => missingKeys.includes(item[pkName]));
   216→                unprocessedItems.push(...missingItems);
   217→            }
   218→        } catch (error) {
   219→            Console.error('Erro ao inserir itens em batch:', error);
   220→        }
   221→    }
   222→
   223→    return unprocessedItems;
   224→  }
   225→
   226→  private removeDuplicates<T>(items: T[]): T[] {
   227→      const seen: Record<string, Set<string>> = {};
   228→      const uniqueItems: T[] = [];
   229→
   230→      items.forEach((item) => {
   231→          const pkValue = (item as {PK: string}).PK;
   232→          const skValue = (item as {SK: string}).SK;
   233→
   234→          if (!seen[pkValue]) {
   235→              seen[pkValue] = new Set();
   236→          }
   237→
   238→          if (!seen[pkValue].has(skValue)) {
   239→              seen[pkValue].add(skValue); 
   240→              uniqueItems.push(item);
   241→          }
   242→      });
   243→
   244→      return uniqueItems;
   245→  }
   246→
   247→}
